import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [cart, setCart] = useState([]);
  const [currentSection, setCurrentSection] = useState('home');

  useEffect(() => {
    loadProducts();
    loadCategories();
    checkUserSession();
    handlePaymentCallback();
  }, []);

  const loadProducts = async () => {
    try {
      const response = await axios.get(`${API_BASE}/products`);
      setProducts(response.data);
    } catch (error) {
      console.error('Error loading products:', error);
    }
  };

  const loadCategories = () => {
    setCategories([
      {id: 1, name: 'Electronics'},
      {id: 2, name: 'Clothing'},
      {id: 3, name: 'Home'}
    ]);
  };

  const checkUserSession = () => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  };

  const handlePaymentCallback = () => {
    const urlParams = new URLSearchParams(window.location.search);
    const status = urlParams.get('status');
    const tx_ref = urlParams.get('tx_ref');

    if (status === 'success' && tx_ref) {
      alert('🎉 Payment Successful!\n\nYour order has been confirmed.\nThank you for shopping with EcoStore!');
      setCart([]);
      setCurrentSection('orders');
      window.history.replaceState({}, document.title, window.location.pathname);
    } else if (status === 'cancelled') {
      alert('❌ Payment Cancelled\n\nYour payment was cancelled.\nYour cart items are still saved.');
      setCurrentSection('cart');
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  };

  const login = async (email, password) => {
    try {
      const response = await axios.post(`${API_BASE}/auth/login`, {
        email, password
      });
      if (response.data.success) {
        setCurrentUser(response.data.user);
        localStorage.setItem('currentUser', JSON.stringify(response.data.user));
        setCurrentSection('home');
        alert('Login successful!');
      } else {
        alert(response.data.message || 'Invalid credentials');
      }
    } catch (error) {
      console.error('Login error:', error);
      alert(error.response?.data?.message || 'Login failed');
    }
  };

  const logout = () => {
    setCurrentUser(null);
    localStorage.removeItem('currentUser');
    setCurrentSection('home');
  };

  const addToCart = (product) => {
    if (!currentUser) {
      if (confirm('You need to login to add items to cart.\n\nClick OK to login or Cancel to register.')) {
        setCurrentSection('login');
      } else {
        setCurrentSection('register');
      }
      return;
    }

    const existingItem = cart.find(item => item.id === product.id);
    if (existingItem) {
      setCart(cart.map(item => 
        item.id === product.id 
          ? {...item, quantity: item.quantity + 1}
          : item
      ));
    } else {
      setCart([...cart, {...product, quantity: 1}]);
    }
    alert('Item added to cart!');
  };

  const removeFromCart = (productId) => {
    setCart(cart.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId, change) => {
    setCart(prevCart => 
      prevCart.map(item => {
        if (item && item.id === productId) {
          const newQuantity = (item.quantity || 0) + change;
          return newQuantity <= 0 ? null : {...item, quantity: newQuantity};
        }
        return item;
      }).filter(item => item !== null)
    );
  };

  return (
    <div className="App">
      <Header 
        currentUser={currentUser} 
        cartCount={cart.reduce((sum, item) => sum + item.quantity, 0)}
        setCurrentSection={setCurrentSection}
        logout={logout}
      />

      {currentSection === 'home' && <Home categories={categories} setCurrentSection={setCurrentSection} />}
      {currentSection === 'products' && 
        <Products products={products} addToCart={addToCart} />}
      {currentSection === 'cart' && 
        <Cart cart={cart} removeFromCart={removeFromCart} updateQuantity={updateQuantity} setCurrentSection={setCurrentSection} />}
      {currentSection === 'checkout' && 
        <Checkout cart={cart} setCart={setCart} currentUser={currentUser} loadProducts={loadProducts} setCurrentSection={setCurrentSection} />}
      {currentSection === 'orders' && currentUser && 
        <OrderHistory currentUser={currentUser} />}
      {currentSection === 'profile' && currentUser && 
        <UserProfile currentUser={currentUser} setCurrentUser={setCurrentUser} />}
      {currentSection === 'login' && <Login onLogin={login} />}
      {currentSection === 'register' && <Register />}
      {currentSection === 'admin' && currentUser?.role === 'admin' && 
        <Admin products={products} loadProducts={loadProducts} />}
      {currentSection === 'seller' && currentUser?.role === 'seller' && 
        <Seller currentUser={currentUser} products={products} loadProducts={loadProducts} />}
    </div>
  );
}

const Header = ({ currentUser, cartCount, setCurrentSection, logout }) => (
  <header className="header">
    <div className="container">
      <div className="logo">
        <h1><i className="fas fa-store"></i> EcoStore</h1>
      </div>
      <nav className="nav">
        <a href="#" onClick={() => setCurrentSection('home')}>Home</a>
        <a href="#" onClick={() => setCurrentSection('products')}>Products</a>
        <a href="#" onClick={() => setCurrentSection('cart')}>Cart ({cartCount})</a>
        {currentUser ? (
          <>
            {currentUser.role === 'admin' && 
              <a href="#" onClick={() => setCurrentSection('admin')}>Admin</a>}
            {currentUser.role === 'seller' && 
              <a href="#" onClick={() => setCurrentSection('seller')}>Seller Dashboard</a>}
            <a href="#" onClick={() => setCurrentSection('orders')}>My Orders</a>
            <a href="#" onClick={() => setCurrentSection('profile')}>My Profile</a>
            <a href="#" onClick={logout}>Logout</a>
          </>
        ) : (
          <>
            <a href="#" onClick={() => setCurrentSection('login')}>Login</a>
            <a href="#" onClick={() => setCurrentSection('register')}>Register</a>
          </>
        )}
      </nav>
    </div>
  </header>
);

const Home = ({ categories, setCurrentSection }) => (
  <section className="section active">
    <div className="hero">
      <h2>Welcome to EcoStore</h2>
      <p>Your one-stop shop with MERN Stack</p>
      <button onClick={() => setCurrentSection('products')} className="btn-primary">Shop Now</button>
    </div>
    <div className="container">
      <div className="categories">
        {categories.map(category => (
          <div key={category.id} className="category" onClick={() => setCurrentSection('products')}>
            <i className={`fas fa-${getCategoryIcon(category.name)}`}></i>
            <h3>{category.name}</h3>
          </div>
        ))}
      </div>
    </div>
  </section>
);

const Products = ({ products, addToCart }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [priceRange, setPriceRange] = useState('all');

  const filteredProducts = products.filter(product => {
    const matchesSearch = searchTerm === '' || 
                         product.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         product.description.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesCategory = selectedCategory === 'all' || 
                           product.category_id === parseInt(selectedCategory);

    const matchesPrice = priceRange === 'all' || 
                        (priceRange === 'under50' && parseFloat(product.price) < 50) ||
                        (priceRange === '50to200' && parseFloat(product.price) >= 50 && parseFloat(product.price) <= 200) ||
                        (priceRange === 'over200' && parseFloat(product.price) > 200);

    return matchesSearch && matchesCategory && matchesPrice;
  });

  return (
    <section className="section active">
      <div className="container">
        <div className="products-header">
          <h2>Products</h2>

          <div className="filters">
            <input
              type="text"
              placeholder="Search products..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="search-input"
            />

            <select 
              value={selectedCategory} 
              onChange={(e) => setSelectedCategory(e.target.value)}
              className="filter-select"
            >
              <option value="all">All Categories</option>
              <option value="1">Electronics</option>
              <option value="2">Clothing</option>
              <option value="3">Home</option>
            </select>

            <select 
              value={priceRange} 
              onChange={(e) => setPriceRange(e.target.value)}
              className="filter-select"
            >
              <option value="all">All Prices</option>
              <option value="under50">Under 50 ETB</option>
              <option value="50to200">50 - 200 ETB</option>
              <option value="over200">Over 200 ETB</option>
            </select>
          </div>
        </div>

        <div className="products-grid">
          {filteredProducts.map(product => (
            <div key={product.id} className="product-card">
              <img src={product.image_url} alt={product.name} className="product-image" />
              <div className="product-info">
                <div className="product-name">{product.name}</div>
                <div className="product-price">{parseFloat(product.price).toFixed(2)} ETB</div>
                <div className="product-description">{product.description}</div>
                <div className={`stock-status ${product.stock > 0 ? 'in-stock' : 'out-of-stock'}`}>
                  {product.stock > 0 ? `In Stock (${product.stock})` : 'Out of Stock'}
                </div>
                <button 
                  onClick={() => addToCart(product)} 
                  className="btn-primary"
                  disabled={product.stock === 0}
                >
                  Add to Cart
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

const Register = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    password: '',
    confirmPassword: '',
    role: 'customer'
  });
  const [passwordStrength, setPasswordStrength] = useState('');

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });

    if (name === 'password') {
      checkPasswordStrength(value);
    }
  };

  const checkPasswordStrength = (password) => {
    if (password.length < 6) {
      setPasswordStrength('weak');
    } else if (password.length < 8 || !/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(password)) {
      setPasswordStrength('medium');
    } else {
      setPasswordStrength('strong');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      alert('Passwords do not match');
      return;
    }

    if (passwordStrength === 'weak') {
      alert('Password is too weak. Use at least 6 characters.');
      return;
    }

    try {
      const response = await axios.post(`${API_BASE}/auth/register`, {
        fullName: formData.fullName,
        email: formData.email,
        password: formData.password,
        role: formData.role
      });

      if (response.data.success) {
        alert('Registration successful! Please login.');
        window.location.reload();
      } else {
        alert(response.data.message || 'Registration failed');
      }
    } catch (error) {
      console.error('Registration error:', error);
      alert('Registration failed. Please try again.');
    }
  };

  return (
    <section className="section active">
      <div className="auth-container">
        <div className="auth-form">
          <h2>Register</h2>
          <form onSubmit={handleSubmit}>
            <input 
              type="text" 
              name="fullName"
              placeholder="Full Name"
              value={formData.fullName}
              onChange={handleInputChange}
              required 
            />
            <input 
              type="email" 
              name="email"
              placeholder="Email"
              value={formData.email}
              onChange={handleInputChange}
              required 
            />
            <input 
              type="password" 
              name="password"
              placeholder="Password"
              value={formData.password}
              onChange={handleInputChange}
              required 
            />
            {formData.password && (
              <div className={`password-strength ${passwordStrength}`}>
                Password strength: {passwordStrength}
              </div>
            )}
            <input 
              type="password" 
              name="confirmPassword"
              placeholder="Confirm Password"
              value={formData.confirmPassword}
              onChange={handleInputChange}
              required 
            />
            <select
              name="role"
              value={formData.role}
              onChange={handleInputChange}
              required
            >
              <option value="customer">Register as Customer</option>
              <option value="seller">Register as Seller</option>
            </select>
            <button type="submit" className="btn-primary">Register</button>
          </form>
        </div>
      </div>
    </section>
  );
};

const Seller = ({ currentUser, products, loadProducts }) => {
  const [activeTab, setActiveTab] = useState('products');
  const [sellerProducts, setSellerProducts] = useState([]);
  const [sellerOrders, setSellerOrders] = useState([]);
  const [sellerEarnings, setSellerEarnings] = useState(null);
  const [showAddProduct, setShowAddProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [productForm, setProductForm] = useState({
    name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''
  });

  useEffect(() => {
    if (activeTab === 'products') loadSellerProducts();
    if (activeTab === 'orders') loadSellerOrders();
    if (activeTab === 'earnings') loadSellerEarnings();
  }, [activeTab]);

  const loadSellerProducts = () => {
    const filtered = products.filter(product => product.seller_id === currentUser.id);
    setSellerProducts(filtered);
  };

  const loadSellerOrders = async () => {
    try {
      const response = await axios.get(`${API_BASE}/seller/orders/${currentUser.id}`);
      setSellerOrders(response.data);
    } catch (error) {
      console.error('Error loading seller orders:', error);
    }
  };

  const loadSellerEarnings = async () => {
    try {
      const response = await axios.get(`${API_BASE}/seller/earnings/${currentUser.id}`);
      setSellerEarnings(response.data);
    } catch (error) {
      console.error('Error loading seller earnings:', error);
    }
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    try {
      const productData = { ...productForm, seller_id: currentUser.id };
      if (editingProduct) {
        await axios.put(`${API_BASE}/seller/products/${editingProduct.id}`, productData);
        alert('Product updated successfully');
      } else {
        await axios.post(`${API_BASE}/seller/products`, productData);
        alert('Product added successfully');
      }
      setShowAddProduct(false);
      setEditingProduct(null);
      setProductForm({name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''});
      loadProducts();
      loadSellerProducts();
    } catch (error) {
      alert('Error saving product');
    }
  };

  const editProduct = (product) => {
    setEditingProduct(product);
    setProductForm({
      name: product.name,
      description: product.description,
      price: product.price,
      stock: product.stock,
      category_id: product.category_id,
      image_url: product.image_url
    });
    setShowAddProduct(true);
  };

  const deleteProduct = async (productId) => {
    if (confirm('Are you sure you want to delete this product?')) {
      try {
        await axios.delete(`${API_BASE}/seller/products/${productId}`);
        loadProducts();
        loadSellerProducts();
        alert('Product deleted successfully');
      } catch (error) {
        alert('Error deleting product');
      }
    }
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>Seller Dashboard</h2>

        <div className="admin-tabs">
          <button 
            className={`tab-btn ${activeTab === 'products' ? 'active' : ''}`}
            onClick={() => setActiveTab('products')}
          >
            My Products
          </button>
          <button 
            className={`tab-btn ${activeTab === 'orders' ? 'active' : ''}`}
            onClick={() => setActiveTab('orders')}
          >
            My Orders
          </button>
          <button 
            className={`tab-btn ${activeTab === 'earnings' ? 'active' : ''}`}
            onClick={() => setActiveTab('earnings')}
          >
            Earnings
          </button>
        </div>

        {activeTab === 'products' && (
          <div className="admin-content">
            <div className="admin-header">
              <h3>Manage My Products</h3>
              <button 
                className="btn-primary"
                onClick={() => setShowAddProduct(true)}
              >
                Add New Product
              </button>
            </div>

            {showAddProduct && (
              <div className="product-form">
                <h4>{editingProduct ? 'Edit Product' : 'Add New Product'}</h4>
                <form onSubmit={handleProductSubmit}>
                  <input
                    type="text"
                    placeholder="Product Name"
                    value={productForm.name}
                    onChange={(e) => setProductForm({...productForm, name: e.target.value})}
                    required
                  />
                  <textarea
                    placeholder="Description"
                    value={productForm.description}
                    onChange={(e) => setProductForm({...productForm, description: e.target.value})}
                    required
                  />
                  <input
                    type="number"
                    placeholder="Price (ETB)"
                    value={productForm.price}
                    onChange={(e) => setProductForm({...productForm, price: e.target.value})}
                    required
                  />
                  <input
                    type="number"
                    placeholder="Stock Quantity"
                    value={productForm.stock}
                    onChange={(e) => setProductForm({...productForm, stock: e.target.value})}
                    required
                  />
                  <select
                    value={productForm.category_id}
                    onChange={(e) => setProductForm({...productForm, category_id: e.target.value})}
                  >
                    <option value="1">Electronics</option>
                    <option value="2">Clothing</option>
                    <option value="3">Home</option>
                  </select>
                  <input
                    type="url"
                    placeholder="Image URL"
                    value={productForm.image_url}
                    onChange={(e) => setProductForm({...productForm, image_url: e.target.value})}
                    required
                  />
                  <div className="form-buttons">
                    <button type="submit" className="btn-primary">
                      {editingProduct ? 'Update Product' : 'Add Product'}
                    </button>
                    <button 
                      type="button" 
                      className="btn-secondary"
                      onClick={() => {
                        setShowAddProduct(false);
                        setEditingProduct(null);
                        setProductForm({name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''});
                      }}
                    >
                      Cancel
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="products-grid">
              {sellerProducts.map(product => (
                <div key={product.id} className="product-card">
                  <img src={product.image_url} alt={product.name} className="product-image" />
                  <div className="product-info">
                    <div className="product-name">{product.name}</div>
                    <div className="product-price">{parseFloat(product.price).toFixed(2)} ETB</div>
                    <div>Stock: {product.stock}</div>
                    <div style={{marginTop: '1rem'}}>
                      <button 
                        className="btn-primary"
                        onClick={() => editProduct(product)}
                      >
                        Edit
                      </button>
                      <button 
                        className="btn-primary" 
                        style={{background: '#dc3545', marginLeft: '0.5rem'}}
                        onClick={() => deleteProduct(product.id)}
                      >
                        Delete
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="admin-content">
            <h3>My Orders</h3>
            <div className="orders-table">
              {sellerOrders.map(order => (
                <div key={order.id} className="order-card">
                  <div className="order-header">
                    <h4>Order #{order.id}</h4>
                    <span className={`order-status ${order.status}`}>{order.status}</span>
                  </div>
                  <div className="order-details">
                    <p><strong>Customer:</strong> {order.customer_name}</p>
                    <p><strong>Total:</strong> {parseFloat(order.total).toFixed(2)} ETB</p>
                    <p><strong>Items:</strong> {order.items}</p>
                    <p><strong>Date:</strong> {new Date(order.created_at).toLocaleDateString()}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'earnings' && (
          <div className="admin-content">
            <h3>My Earnings</h3>
            {sellerEarnings && (
              <div className="earnings-summary">
                <div className="earnings-cards">
                  <div className="earnings-card">
                    <h4>Total Sales</h4>
                    <p className="earnings-amount">{parseFloat(sellerEarnings.total_sales || 0).toFixed(2)} ETB</p>
                  </div>
                  <div className="earnings-card">
                    <h4>Platform Commission ({sellerEarnings.commission_rate || 10}%)</h4>
                    <p className="earnings-amount">-{parseFloat(sellerEarnings.total_commission || 0).toFixed(2)} ETB</p>
                  </div>
                  <div className="earnings-card">
                    <h4>My Earnings</h4>
                    <p className="earnings-amount">{parseFloat(sellerEarnings.net_earnings || 0).toFixed(2)} ETB</p>
                  </div>
                  <div className="earnings-card">
                    <h4>Pending Payout</h4>
                    <p className="earnings-amount pending">{parseFloat(sellerEarnings.pending_amount || 0).toFixed(2)} ETB</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </section>
  );
};

const getCategoryIcon = (categoryName) => {
  const icons = {
    'Electronics': 'laptop',
    'Clothing': 'tshirt',
    'Home': 'home'
  };
  return icons[categoryName] || 'box';
};

// Placeholder components - add your existing Cart, Checkout, Login, OrderHistory, UserProfile, Admin components here
const Cart = () => <div>Cart Component</div>;
const Checkout = () => <div>Checkout Component</div>;
const Login = () => <div>Login Component</div>;
const OrderHistory = () => <div>OrderHistory Component</div>;
const UserProfile = () => <div>UserProfile Component</div>;
const Admin = () => <div>Admin Component</div>;

export default App;
